theme_css_usage.css_example:
/* In theme CSS files - HubL processes {{ }} in CSS */
body {
  font-family: {{ theme.typography.h1_font.font }}, sans-serif;
  color: {{ theme.colors.primary.color }};
  background-color: {{ theme.colors.background.color }};
}

h1 {
  font-size: {{ theme.typography.h1_font.size }}{{ theme.typography.h1_font.size_unit }};
  font-weight: {{ theme.typography.h1_font.bold ? 'bold' : 'normal' }};
}

theme_css_usage.template_example:
{# In .html templates #}
{% if theme.colors.primary.color %}
<style>:root { --primary: {{ theme.colors.primary.color }}; }</style>
{% endif %}
